from abc import ABC, abstractmethod
from typing import Set

from geosat.psanp.abstractions.stage import Stage


class IClassifier(ABC):
    @abstractmethod
    def input_classes(self) -> Set[str]:
        """In this method, the classifier
        shall return the class names it expects to exist in the cloud

        It can be empty.

        For example a ``RoadClassifier`` may work on the points classified
        as 'ground' so it should return ``{"ground"}``.

        .. note::

            Whatever the returned value is, the point cloud
            that the classifier will receive will be the whole point cloud
            (eg: The ``RoadClassifier`` receives the whole point cloud, not just
            point classifier as "ground")

            This is the way **PSANP** has to verify that if classifier B needs
            the class 'A' to exist in the cloud, then there is a classifier
            that outputs class 'A' that is run before classifier B.

            In our ``RoadClassifier`` that needs the ground, if no ``GroundClassifier``
            is declared to run before in the pipeline definition then the
            pipeline won't start.
            However, if there's a ``GroundClassifier``, but it finds no ground (for
            whatever reason) then this is the job of the ``RoadClassifier`` to
            handle that (in that case by doing nothing)

        :return: set of class names the classifier works on
        """

    @abstractmethod
    def output_classes(self) -> Set[str]:
        """in this method the classifier
        shall return the class names it classifies

        It can be empty.

        For example a ``RoadClassifier`` that creates a class called "road"
        then this method shall return ``{"road"}``

        :return: set of class names this classifier creates
        """


class Classifier(Stage, IClassifier, ABC):
    ...
